            className="rounded-full absolute top-0 left-0 z-0"
            width={300}
            height={300}
            src="/Foto4.HEIC"
            alt="Imagen 2"
          />
        </div>

        <div className="flex flex-col items-center">
          <h1 className="text-white text-4xl md:text-6xl font-bold text-center">
            ¡Los invitamos a festejar nuestra boda!
          </h1>
          <h2 className="text-white text-4xl md:text-6xl font-bold text-center">
            Anto & Kevin
          </h2>
          <a
            href="#ConfirmAttendance"
            className="text-white text-xl mt-4 underline hover:text-gray-200"
          >
            {`Confirmar asistencia ${'>'}`}
          </a>
        </div>

        <div>
          <img width={300} height={300} src="/Foto4.HEIC" alt="Imagen 3" />
          <img width={300} height={300} src="/Foto4.HEIC" alt="Imagen 4" />
        </div>
      </div>
    </div>
  );
}

export default Home;
